In the Go Kubernetes ecosystem, you don't write the API server listeners from scratch - a framework called Kubebuilder (or Operator SDK) generates that boilerplate. Your job is to write the Reconciler Loop (Phase II), the Translation Logic (Phase III), and the Status Sync (Phase IV).

Prerequisite structs (in a real project these are auto-generated from CRD YAML, shown here for clarity):

```go
package controllers

import (
	"context"
	"fmt"

	"k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/types"
	ctrl "sigs.k8s.io/controller-runtime"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/controller/controllerutil"

	opiv1 "github.com/yourorg/middleman/api/opi/v1"
	dpfv1 "github.com/yourorg/middleman/api/dpf/v1"
)
```

Phase II - The Reconciler Engine (S_(t+1) = R(S_t, I)):

```go
type OpiReconciler struct {
	client.Client
	Scheme *runtime.Scheme
}

// +kubebuilder:rbac:groups=opi.api.com,resources=opiresources,verbs=get;list;watch;create;update;patch;delete
// +kubebuilder:rbac:groups=dpf.nvidia.com,resources=dpuservices,verbs=get;list;watch;create;update;patch;delete

func (r *OpiReconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
	log := ctrl.LoggerFrom(ctx)

	// 1. Fetch the OPI Intent (the input, X)
	var opiIntent opiv1.OpiResource
	if err := r.Get(ctx, req.NamespacedName, &opiIntent); err != nil {
		if errors.IsNotFound(err) {
			// object deleted - Kubernetes garbage collection handles DPF deletion automatically
			return ctrl.Result{}, nil
		}
		return ctrl.Result{}, err
	}

	// 2. Phase III: Translation (T: X -> Y)
	dpfTarget := r.translateOpiToDpf(&opiIntent)

	// 3. Garbage collection ownership
	if err := controllerutil.SetControllerReference(&opiIntent, dpfTarget, r.Scheme); err != nil {
		return ctrl.Result{}, err
	}

	// 4. Apply to hardware
	var existingDpf dpfv1.DPUService
	err := r.Get(ctx, types.NamespacedName{Name: dpfTarget.Name, Namespace: dpfTarget.Namespace}, &existingDpf)

	if err != nil && errors.IsNotFound(err) {
		log.Info("Creating new DPF Service for hardware actuation", "Name", dpfTarget.Name)
		if err := r.Create(ctx, dpfTarget); err != nil {
			return ctrl.Result{}, err
		}
	} else if err == nil {
		log.Info("Updating existing DPF Service", "Name", dpfTarget.Name)
		existingDpf.Spec = dpfTarget.Spec
		if err := r.Update(ctx, &existingDpf); err != nil {
			return ctrl.Result{}, err
		}
	} else {
		return ctrl.Result{}, err
	}

	// 5. Phase IV: Status feedback
	return r.syncStatus(ctx, &opiIntent, &existingDpf)
}
```

Phase III - Translation Matrix implementation:

```go
func (r *OpiReconciler) translateOpiToDpf(opi *opiv1.OpiResource) *dpfv1.DPUService {
	dpf := &dpfv1.DPUService{
		ObjectMeta: metav1.ObjectMeta{
			Name:      fmt.Sprintf("%s-dpf-backend", opi.Name),
			Namespace: opi.Namespace,
			Labels:    map[string]string{"managed-by": "opi-dpf-middleman"},
		},
		Spec: dpfv1.DPUServiceSpec{
			ServiceType: "OVS",
			Image:       "nvcr.io/nvidia/doca/ovs:latest",
			NodeSelector: map[string]string{
				"k8s.ovn.org/dpu-host": "true",
			},
			Network: dpfv1.NetworkSpec{
				Vlan: opi.Spec.VlanId,
			},
			Interfaces: []dpfv1.InterfaceSpec{
				{MacAddress: opi.Spec.MacAddress},
			},
			QosConfig: dpfv1.QosSpec{
				MaxBandwidthBytes: opi.Spec.Qos.BandwidthLimitGbps * 125000000,
			},
		},
	}
	return dpf
}
```

Phase IV - Status Feedback Loop implementation:

```go
func (r *OpiReconciler) syncStatus(ctx context.Context, opi *opiv1.OpiResource, dpf *dpfv1.DPUService) (ctrl.Result, error) {
	newStatus := "Pending"
	if dpf.Status.HardwareState == "Provisioned" {
		newStatus = "Ready"
	} else if dpf.Status.HardwareState == "Failed" {
		newStatus = "Error"
	}

	if opi.Status.Phase != newStatus {
		opi.Status.Phase = newStatus
		if err := r.Status().Update(ctx, opi); err != nil {
			return ctrl.Result{}, err
		}
	}

	return ctrl.Result{}, nil
}
```

Scaffolding commands to wire this into a real project:

```
go mod init github.com/your-username/opi-dpf-middleman
kubebuilder init --domain api.com --repo github.com/your-username/opi-dpf-middleman
kubebuilder create api --group opi --version v1 --kind OpiResource
```

Paste the Reconciler logic above into internal/controller/opiresource_controller.go.
